package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{"Header"}, new String[]{"Name", "Age"}, false, true, true, false, true);

        // When
        boolean isCommentMarkerSet = csvFormat.isCommentMarkerSet();

        // Then
        assertEquals(true, isCommentMarkerSet);
    }
}
